  ('immigration-1aab856d-moex-00333', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '有關入出國及移民法第 18 條之禁止外國人入國案件，對於禁止外國人入國期間之敘述，下列何 者錯誤？ 瞞重要事實者，禁止入國5年 10年 10年 3年', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "915043464e38", "answer_pdf_sha1": "a0fbd6c95be1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
